mapper.select:
select mi.*, m.name, me.bar_code, m.color_code, m.color, m.model, u.name unit, ps.models_combined supplier_model, m.other_field5 other_field5 from jsh_material_initial_stock mi left join jsh_material m on m.id = mi.material_id and ifnull(m.delete_Flag,'0') !='1' left join jsh_material_extend me on m.id=me.material_id and ifnull(me.delete_Flag,'0') !='1' left join jsh_unit u on m.unit_id=u.id and ifnull(u.delete_Flag,'0') !='1' left join (select bar_code, delete_Flag, GROUP_CONCAT(model SEPARATOR ';') as models_combined from jsh_product_supplier where ifnull(delete_Flag,'0') !='1' GROUP BY bar_code) ps on me.bar_code = ps.bar_code and ifnull(ps.delete_Flag,'0') !='1' where mi.depot_id=-1
and (me.bar_code like #{bindKey} or m.name like #{bindKey} or m.color_code like #{bindKey} or m.other_field5 like #{bindKey} or ps.models_combined like #{bindKey} or m.model like #{bindKey})
and m.category_id in
#{item}
and ifnull(mi.delete_flag,'0') !='1' order by mi.id desc
limit #{offset},#{rows}

